"use client"

import Cookies from "js-cookie"

import {
  Users,
  Laptop,
  ClipboardList,
  Activity,
} from "lucide-react"

export default function Sidebar() {
  return (
    <aside className="w-72 bg-[#111827] text-white p-8 flex flex-col justify-between min-h-screen">

      <div>

        <div className="mb-14">

          <h1 className="text-4xl font-black tracking-tight">
            Bank Waway
          </h1>

          <p className="text-gray-400 mt-2 text-sm">
            HRGA Enterprise System
          </p>

        </div>

        <nav className="space-y-3">

          <button className="w-full flex items-center gap-4 bg-white/10 hover:bg-white/20 transition-all duration-200 p-4 rounded-2xl">

            <Users size={20} />

            <span className="font-medium">
              Employees
            </span>

          </button>

          <button className="w-full flex items-center gap-4 hover:bg-white/10 transition-all duration-200 p-4 rounded-2xl">

            <Laptop size={20} />

            <span className="font-medium">
              Assets
            </span>

          </button>

          <button className="w-full flex items-center gap-4 hover:bg-white/10 transition-all duration-200 p-4 rounded-2xl">

            <ClipboardList size={20} />

            <span className="font-medium">
              Requests
            </span>

          </button>

          <button className="w-full flex items-center gap-4 hover:bg-white/10 transition-all duration-200 p-4 rounded-2xl">

            <Activity size={20} />

            <span className="font-medium">
              Audit Logs
            </span>

          </button>

        </nav>

      </div>

      <button
        onClick={() => {
          Cookies.remove("token")
          window.location.href = "/login"
        }}
        className="bg-red-500 hover:bg-red-600 transition-all duration-200 p-4 rounded-2xl font-semibold mt-10"
      >
        Logout
      </button>

    </aside>
  )
}